import { Component, h, Host, Listen, Prop, State, Element, Method, Watch } from '@stencil/core';
import { addGlobalStylesToShadowRoot, isNullOrUndefined } from '@src/utils/mx-utils/utils';
import { IVerticalNavItem, IVerticalNavUserMenuItem } from './mx-vertical-nav.interface';
import {
  IVerticalNavPanelItem
} from '@src/mx-components/layout/mx-vertical-nav/mx-vertical-nav-panel/mx-vertical-nav-panel';

/**
 * The global navigation is a configurable navigation element with sub-menu capabilities. 
 * It is a panel that stretches top to bottom along the left side of a page and displays links to different pages or parts of an application.
 */
@Component({
  tag: 'mx-vertical-nav',
  styleUrl: 'mx-vertical-nav.css',
  shadow: true
})
export class MxVerticalNav {

  @Element() hostElement: HTMLMxVerticalNavElement;

  /** Sets the app title in the top bar. */
  @Prop() readonly appTitle: string;

  /** Sets the items of the vertical navigation panel. */
  @Prop() readonly items: Array<IVerticalNavItem>;

  /** Sets the items of the user menu in the popup on user click. */
  @Prop({ mutable: true })  userItems: Array<IVerticalNavUserMenuItem>;

  /** Keeps the panel with the navigation opened. Click outside the navigation panel will be ignored. */
  @Prop() readonly keepPanelOpen: boolean;

  /** Sets the number of columns on the vertical nav sub-menus. */
  @Prop() readonly subMenuColumns: number = 1;

  /** Sets the merch hub link inside the nav. */
  @Prop() readonly mxhMerchHubLink: string = 'https://mx.kroger.com/';

  /** Sets the merch hub app menu items. */
  @Prop() readonly mxhApps: Array<IVerticalNavItem>;

  /** Sets the merch hub link menu items. */
  @Prop() readonly mxhLinks: Array<IVerticalNavItem>;

  /** Sets the merch hub report group(s) items. */
  @Prop() readonly mxhReports: Array<IVerticalNavItem>;

  /** Navigation panel open state  */
  @Prop({ mutable: true }) opened = false;

  @Watch('items')
  onItemsChange(newValue: IVerticalNavItem[]) {
    if (!this.opened) {
      newValue.forEach((item: IVerticalNavItem) => {
        if (item.showSubMenu) {
          this.opened = true;
          this.verticalNavPanelRef.openPanel();
        }
      });
    }
  }

  /** User menu open state  */
  @State() userMenuOpened = false;
  @State() hamburgerMenuShownStatus = true;
  @State() _panelItems: IVerticalNavPanelItem[] = [];

  private verticalNavPanelRef: HTMLMxVerticalNavPanelElement;

  @Listen('subMenuLinkClicked')
  onSubmenuLinkClicked(event) {
    this.verticalNavPanelRef.closePanel();
    // If there are any visible sub menus when we close the vertical panel, we should hide them.
    const allShownSubMenus = Array.from(document.getElementsByTagName('mx-vertical-nav-sub-menu'))
      .filter((subMenu) => subMenu.show);
    allShownSubMenus.forEach((subMenu) => subMenu.show = false);
    this.selectItem(event.detail);
  }

  @Listen('userProfileItemSelected')
  onItemSelected(event){
    this.handleItemSelected(event.detail.label);
  }

  @Listen('clickHandler')
  onItermClicked(event) {
    const item = event.detail;
    if (this.allSubItemsHidden(item)) {
      this.selectItem(item);
    }
  }

  componentWillLoad() {
    this.hostElement.shadowRoot && addGlobalStylesToShadowRoot(this.hostElement.shadowRoot);
    if (this.mxhReports && this.mxhReports.length > 5) {
      console.warn('mx-vertical-nav: Only a maximum of 5 report groups are supported.');
    }
  }

  componentWillRender() {
    this._panelItems = this.composePanelItems();
  }

  private readonly allSubItemsHidden = (item: IVerticalNavItem): boolean => {
    const children = item.children;
    const hasChildren = children != null && children.length > 0;
    if (hasChildren) {
      if (children.filter((ch) => ch.shouldHide).length == children.length) {
        return true;
      }
      let allSubChildrenHidden = true;
      children.forEach((ch) => {
        allSubChildrenHidden = allSubChildrenHidden &&
          ch.children.filter((ch2) => ch2.shouldHide).length === ch.children.length;
      });
      return allSubChildrenHidden;
    }
    return true;
  };

  private readonly onHamburgerMenuClick = (event: CustomEvent<boolean>) => {
    const showStatus = event.detail;
    if (showStatus) {
      this.verticalNavPanelRef.openPanel();
    } else {
      this.verticalNavPanelRef.closePanel();
    }
    this.opened = event.detail;
  };

  /** Selects the item in the nav */
  @Method()
  public async selectItem(itemLableOrItemObject: string | IVerticalNavItem, deSelectOthers = true) {
    const isLabelPassed: boolean = typeof itemLableOrItemObject === 'string';
    const itemToSelectObject: IVerticalNavItem = isLabelPassed ? null : itemLableOrItemObject as IVerticalNavItem;
    const itemLabel: string = isLabelPassed ? itemLableOrItemObject as string : itemToSelectObject.label;
    const itemLink: string = isLabelPassed ? '' : itemToSelectObject.link;
    this._panelItems = [...this._panelItems.map((item) => {
      if (item.isDivider) {
        return item;
      }
      item = { ...item, selected: this.checkSelectedItem(item, itemLabel, itemLink, deSelectOthers) };
      if (item.children != null) {
        item.children = [...item.children.map((ch1: IVerticalNavItem) => {
          if (ch1.children != null) {
            ch1.children = [...ch1.children.map((ch2: IVerticalNavItem) => {
              ch2.selected = this.checkSelectedItem(ch2, itemLabel, itemLink, deSelectOthers);
              return ch2;
            })];
          } else {
            ch1.selected = this.checkSelectedItem(ch1, itemLabel, itemLink, deSelectOthers);
          }
          return ch1;
        })];
      }
      return item;
    })];
  }

  private checkSelectedItem(
    item: IVerticalNavItem,
    label: string,
    link: string,
    deSelectOthers = true): boolean {
    const sameLabel: boolean = item.label === label;
    const sameLink: boolean = link === '' || item.link === link;
    return (item.selected && !deSelectOthers) || (sameLabel && sameLink);
  }

  /** Deselects all the items in the nav */
  @Method()
  public async deSelectItems() {
    await this.selectItem(null);
  }

  /** Show sub menu of the item */
  @Method()
  public async showItemSubMenu(itemLabel: string, closeOthers = true) {
    this._panelItems = [...this._panelItems.map((item) => {
      return item.isDivider ?
        item :
        { ...item, showSubMenu: (item.showSubMenu && !closeOthers) || item.label === itemLabel };
    })];
  }

  /** Hides all opened submenus */
  @Method()
  public async hideAllItemSubMenus() {
    await this.showItemSubMenu(null);
  }

  /** Disables submenu item */
  @Method()
  public async disableSubMenuItem(itemLabel: string, info: string = null) {
    this._panelItems = this.setSubmenuItemDisabledState(itemLabel, true, info);
  }

  /** Selects User profile item */
  @Method()
  public async handleItemSelected (itemLabel: string, deSelectOthers = true) {
    this.userItems = [...this.userItems.map((item) => {
      return { ...item, selected: (item.selected && !deSelectOthers) || item.label === itemLabel };
    })];
  }

  /** Enables submenu item */
  @Method()
  public async enableSubMenuItem(itemLabel: string) {
    this._panelItems = this.setSubmenuItemDisabledState(itemLabel, false, null);
  }

  private setSubmenuItemDisabledState(itemLabel, disabled, disabledInfo): Array<IVerticalNavItem> {
    return [...this._panelItems.map((item) => {
      if (item.children != null) {
        item.children = [...item.children.map((ch1) => {
          if (ch1.children != null) {
            ch1.children = [...ch1.children.map((ch2) => {
              if (ch2.label === itemLabel) {
                ch2.disabled = disabled;
                ch2.disabledInfo = disabled ? null : disabledInfo;
              }
              return ch2;
            })];
          }
          return ch1;
        })];
      }
      return item;
    })];
  }

  private readonly updateHamburgerMenuShownStatus = (event: CustomEvent<boolean>) => {
    this.hamburgerMenuShownStatus = event.detail;
  };

  private readonly composePanelItems = (): IVerticalNavPanelItem[] => {
    const hasCommonItems: boolean = !isNullOrUndefined(this.items);
    const items: IVerticalNavPanelItem[] = !hasCommonItems ?
      [] :
      this.items.map((item: IVerticalNavItem) => {
        return {
          ...item,
          isDivider: false,
          columns: this.subMenuColumns
        };
      });
    const hasMxHApps: boolean = this.mxhApps && this.mxhApps.length > 0;
    const hasMxHReports: boolean = this.mxhReports && this.mxhReports.length > 0;
    const hasMxHLinks: boolean = this.mxhLinks && this.mxhLinks.length > 0;
    // you can add condition here if you need more merchhub specific items
    const hasMerchHubLink: boolean = hasMxHApps || hasMxHReports || hasMxHLinks;
    const hasDivider: boolean = hasCommonItems && hasMerchHubLink;
    if (hasDivider) {
      items.push({ isDivider: true, label: 'divider', link: '' });
    }

    if (hasMerchHubLink) {
      items.push({
        label: 'Merch Hub',
        link: this.mxhMerchHubLink || '',
        icon: 'mx-mh-icon',
        clickHandler: () => {
          window.open(this.mxhMerchHubLink, '_blank');
        }
      });
    }

    if (hasMxHApps) {
      const { children, columns } = this.composeChildrenInColumnsForMXH(this.mxhApps);
      const myAppsItem: IVerticalNavPanelItem = {
        label: 'Apps',
        link: '',
        children: children,
        icon: 'kds-icon-laptop',
        columns: columns,
        isDivider: false
      };
      items.push(myAppsItem);
    }

    if (hasMxHLinks) {
      const { children, columns } = this.composeChildrenInColumnsForMXH(this.mxhLinks);
      const myLinkItem: IVerticalNavPanelItem = {
        label: 'My Links',
        link: '',
        children: children,
        icon: 'kds-icon-link',
        columns: columns,
        isDivider: false
      };
      items.push(myLinkItem);
    }

    if (hasMxHReports) {
      for (let r = 0; r < (Math.min(this.mxhReports.length, 5)); r++) {
        const { children, columns } = this.composeChildrenInColumnsForMXH(this.mxhReports[r].children);
        const myReportGroupItem: IVerticalNavPanelItem = {
          label: this.mxhReports[r].label,
          link: '',
          children,
          icon: 'kds-icon-expense-report',
          columns,
          isDivider: false
        };
        items.push(myReportGroupItem);
      }
    }
    // when add new items here, please use 'hasMxHApps' variable to determine if we still need a divider here
    return items;
  }

  private composeChildrenInColumnsForMXH(items): { children: IVerticalNavPanelItem[], columns: number } {
    const children: IVerticalNavPanelItem[] = [];
    const columns = Math.ceil(items.length / 10);
    for (let i = 0; i < columns; i++) {
      // flatten the list into groups of 10, that way 1 column can contain a max of 10 items
      children.push({
        label: '',
        link: '',
        children: items
          .slice(i * 10, (i + 1) * 10)
          .map((app: IVerticalNavPanelItem) => {
            return {
              ...app,
              // overriding this so that all merch hub specific links force to open in a new tab
              defaultBrowserNavigation:  true,
              target:  '_blank',
              clickHandler: null
            };
          })
      });
    }
    return { children, columns };
  }

  render() {
    const showHamburgerMenu = this.hamburgerMenuShownStatus &&
      !isNullOrUndefined(this._panelItems) &&
      this._panelItems.length > 0;
    return (
      <Host>
        <div class='mx-vertical-nav'>
          <mx-vertical-nav-header
            appTitle={this.appTitle}
            opened={this.opened}
            userItems={this.userItems}
            showHamburgerMenu={showHamburgerMenu}
            onHamburgerMenuClick={this.onHamburgerMenuClick}
          >
            <div slot='inner-logo'> <slot name='logo' /> </div>
            <div class='w-full flex justify-end' slot='inner-center-block'><slot name='center-block' /></div>
            <div slot='inner-user'> <slot name='user' /> </div>
          </mx-vertical-nav-header>
          <mx-vertical-nav-panel
            opened={this.opened}
            items={this._panelItems}
            keepPanelOpen={this.keepPanelOpen}
            onUpdateHamburgerMenuShownStatus={this.updateHamburgerMenuShownStatus}
            ref={(ref) => this.verticalNavPanelRef = ref}>
            <slot />
          </mx-vertical-nav-panel>
        </div>
      </Host>
    );
  }
}
